/**
 * Build the AssetRiskInput exactly as the live adapter would, for a window
 * ending at `endIdx`: 30 daily returns (asset + BTC proxy) and 90d extremes.
 */
export function assetRiskAt(
  asset: readonly number[],
  btc: readonly number[],
  endIdx: number,
): AssetRiskInput {
  const assetWin = asset.slice(endIdx - 30, endIdx + 1); // 31 prices → 30 returns
  const btcWin = btc.slice(endIdx - 30, endIdx + 1);
  const win90 = asset.slice(0, endIdx + 1); // idx 0 ≈ 90 days before Mar 9
  return {
    dailyReturns30d: dailyReturns(assetWin),
    btcReturns30d: dailyReturns(btcWin),
    maxPrice90d: Math.max(...win90),
    minPrice90d: Math.min(...win90),
  };
}
